  render: () => {
    function CollapsedExample() {
      const {
        setContent
      } = useInfobar();
      React.useEffect(() => {
        setContent(sampleContent);
      }, [setContent]);
      return <div className="flex h-[500px]">
          <Infobar collapsible="icon">
            <InfobarContent>
              <InfobarMenu>
                <InfobarMenuItem>
                  <InfobarMenuButton isActive>
                    <Icons.dashboard />
                    <span>Overview</span>
                  </InfobarMenuButton>
                </InfobarMenuItem>
                <InfobarMenuItem>
                  <InfobarMenuButton>
                    <Icons.trendingUp />
                    <span>Analytics</span>
                  </InfobarMenuButton>
                </InfobarMenuItem>
              </InfobarMenu>
            </InfobarContent>
          </Infobar>
          <InfobarRail />
          <InfobarInset>
            <div className="p-8">
              <h1 className="text-2xl font-bold">Collapsed View</h1>
            </div>
          </InfobarInset>
        </div>;
    }
    return <CollapsedExample />;
  }
