  render: () => {
    function FixedExample() {
      const {
        setContent
      } = useInfobar();
      React.useEffect(() => {
        setContent(sampleContent);
      }, [setContent]);
      return <div className="flex h-[500px]">
          <Infobar collapsible="none">
            <InfobarHeader>
              <h2 className="text-sm font-semibold">Fixed Sidebar</h2>
            </InfobarHeader>
            <InfobarSeparator />
            <InfobarContent>
              <p className="text-sm text-muted-foreground">This sidebar cannot be collapsed.</p>
            </InfobarContent>
          </Infobar>
          <InfobarInset>
            <div className="p-8">
              <h1 className="text-2xl font-bold">Fixed Infobar</h1>
            </div>
          </InfobarInset>
        </div>;
    }
    return <FixedExample />;
  }
