  render: () => {
    function SkeletonExample() {
      const {
        setContent
      } = useInfobar();
      React.useEffect(() => {
        setContent(sampleContent);
      }, [setContent]);
      return <div className="flex h-[500px]">
          <Infobar>
            <InfobarHeader>
              <InfobarInput placeholder="Search..." />
            </InfobarHeader>
            <InfobarSeparator />
            <InfobarContent>
              <InfobarGroup>
                <InfobarGroupLabel>Loading...</InfobarGroupLabel>
                <InfobarMenu>
                  <InfobarMenuSkeleton showIcon />
                  <InfobarMenuSkeleton />
                  <InfobarMenuSkeleton showIcon />
                  <InfobarMenuSkeleton />
                  <InfobarMenuSkeleton showIcon />
                </InfobarMenu>
              </InfobarGroup>
            </InfobarContent>
          </Infobar>
          <InfobarRail />
          <InfobarInset>
            <div className="p-8">
              <h1 className="text-2xl font-bold">With Skeleton Loading</h1>
            </div>
          </InfobarInset>
        </div>;
    }
    return <SkeletonExample />;
  }
